*/

const int maxVelocity = 20;
const int minVelocity = -10;
const int radarRange = 100; /// maximum range radar can see

int distance = 10;           /// integer estimate of distance between cars

int velocityEgo;             /// integer estimate of Ego velocity
int[-2,2] accelerationEgo;   /// acceleration of Ego
broadcast chan chooseEgo;    /// signal to Ego to decide

int velocityFront;           /// integer estimate of Front velocity
int[-2,2] accelerationFront; /// acceleration of Front
broadcast chan chooseFront;  /// signal to Front to decide
broadcast chan update;       /// check if Front is still within radar range

int velocityBack;             /// integer estimate of Back velocity
int[-2,2] accelerationBack;  /// acceleration of Back
broadcast chan chooseBack;    /// signal to Back to decide

/// Estimate velocities and distance using integers after 1s
void updateDiscrete() {
    int oldVel = velocityFront - velocityEgo;
    int newVel;
    velocityEgo = velocityEgo + accelerationEgo;
    velocityFront = velocityFront + accelerationFront;
    newVel = velocityFront - velocityEgo;
    if (distance <= radarRange)
        distance += (oldVel + newVel)/2;
    else
        distance = radarRange + 1;
}

/// Continuous (realistic) state of the system:
hybrid clock rVelocityBack;   /// velocity of Back
hybrid clock rVelocityEgo;   /// velocity of Ego
hybrid clock rVelocityFront; /// velocity of Front
hybrid clock rDistance = 10; /// distance between cars Ego and Fron
hybrid clock rDistanceB = 10; /// distance between cars Back and Ego
hybrid clock D; /// "cost" of distance used in strategy optimization for Ego
hybrid clock DB; /// "cost" of distance used in strategy optimization for Back


double relVelocity(double velFront, double velEgo, double dist) {
    if (dist <= radarRange)
        return velFront - velEgo;
    else
        return 0.0;
}

int takeAction() {
    if (rDistance <= 27.20512820512822) {
    if (rDistance <= 2.126262626262627) {
      if (rVelocityEgo - rVelocityFront <= -0.8717948717948721) {
        if (rVelocityEgo - rVelocityFront <= -4.222222222222222) {
          return 2;
        } else {
          return 0;
        }
      } else {
        if (rVelocityEgo - rVelocityFront <= 1.366972477064221) {
          if (rDistance <= -5.14406779661017) {
            return 0;
          } else {
            if (rDistance <= 1.576086956521739) {
              return 2;
            } else {
              return 0;
            }
          }
        } else {
          return 0;
        }
      }
    } else {
      if (rVelocityEgo - rVelocityFront <= -0.05809128630705396) {
        if (rVelocityEgo - rVelocityFront <= -3.04602510460251) {
          return 1;
        } else {
          if (rDistance <= 12.6524064171123) {
            return 2;
          } else {
            return 1;
          }
        }
      } else {
        if (rVelocityEgo - rVelocityFront <= 1.366972477064221) {
          if (rDistance <= 8.290229885057471) {
            return 0;
          } else {
            if (rDistance <= 21.61122244488978) {
              return 2;
            } else {
              return 1;
            }
          }
        } else {
          if (rDistance <= 25.33333333333331) {
            return 0;
          } else {
            if (rVelocityEgo - rVelocityFront <= 2.031914893617022) {
              return 2;
            } else {
              return 0;
            }
          }
        }
      }
    }
  } else {
    if (rVelocityEgo - rVelocityFront <= 1.366972477064221) {
      if (rVelocityEgo - rVelocityFront <= -1.683673469387755) {
        return 1;
      } else {
        if (rDistance <= 29.78947368421052) {
          return 2;
        } else {
          if (rDistance <= 31.08088235294118) {
            return 2;
          } else {
            return 1;
          }
        }
      }
    } else {
      if (rVelocityEgo - rVelocityFront <= 2.031914893617022) {
        if (rDistance <= 34.27780898876405) {
          if (rDistance <= 29.78947368421052) {
            return 2;
          } else {
            return 0;
          }
        } else {
          if (rDistance <= 38.22881355932201) {
            return 2;
          } else {
            return 0;
          }
        }
      } else {
        return 0;
      }
    }
  }

}

void egoChoose() {
    int action = takeAction();
    if (action == 0) {
        accelerationEgo = -2;
    } else if (action == 1) {
        accelerationEgo = 2;
    } else {
        accelerationEgo = 0;
    }
}

/*
Hybrid clocks:
- Usually represent some continuous (dynamical) cost over the system state space.
- Can be used in rate (derivative) expressions.
- Cannot be used in constraints (guards and invariants).
- Are abstracted away and have no effect in symbolic analysis (Symbolic Simulator, queries like A[], E<>, TIGA safety synthesis), we can do this, because they do not influence the logic of the model.
- Are used in concrete simulations (Concrete Simulator, SMC queries like simulate, Pr, minE, maxE, E[...](max:)).
*/

nta.system:
clock time;
//system Back, Ego2, Front, Decisions, Dynamics;
system Ego, Front, Decisions, Dynamics;
